   ========================= */
const clean = (str) => String(str || '').replace(/\n/g, '').replace(/\s+/g, ' ');

const stripEllipsis = (val) => String(val || '')
  .replace(/max-width:[^;]+;/g, '')
  .replace(/overflow:hidden;/g, '')
  .replace(/white-space:nowrap;/g, '')
  .replace(/text-overflow:ellipsis;/g, '');

/* FIX: only sanitize arrow-like glitch characters */
/* FIX: sanitize arrow-like glitch characters and box/symbol artifacts */
/* FIX: strip ALL non-ASCII symbols and replace with safe HTML arrows */
/* FIX: strip ALL non-ASCII symbols EXCEPT bullet (•) and replace with safe HTML arrows */
const fixArrows = (text) => {
  if (!text) return "";
  let s = String(text);
  // Detect direction before stripping
  const hasUp = /[▲▴▵△⬆🔺↑⬈↗]/u.test(s) || /\+/.test(s);
  const hasDown = /[▼▾▿▽⬇🔻↓⬊↘]/u.test(s) || /\-/.test(s);
  // Strip ALL non-printable-ASCII characters EXCEPT bullet (•) U+2022
  s = s.replace(/[^\x20-\x7E\u2022]/g, "").replace(/\s+/g, " ").trim();
  // Prepend a safe HTML arrow if we detected direction
  if (hasUp) s = "&#9650; " + s;
  else if (hasDown) s = "&#9660; " + s;
  return s;
};

/* Sanitize insight text: strip glitchy chars but keep bullets, no arrow prepend */
const cleanInsightText = (text) => {
  if (!text) return "";
  return String(text)
    .replace(/[^\x20-\x7E\u2022]/g, "")
    .replace(/\s+/g, " ")
    .trim();
};

const sortByClicksDesc = (arr) => {
  return [...arr].sort((a, b) => Number(b.clicks || b.Clicks) - Number(a.clicks || a.Clicks));
};

const fmtTime = (s) => {
  const m = Math.floor(s / 60);
  const sec = Math.round(s % 60);
  return m > 0 ? m + "m " + sec + "s" : sec + "s";
};

/* =========================
