   ========================= */
const formatInsights = (text) => {
  if (!text) return "";
  const cleaned = cleanInsightText(text);
  const points = cleaned.split("\u2022").filter(p => p.trim() !== "");
  return `
    <div style="display:flex;flex-direction:column;gap:14px;">
      ${points.map(p => {
        const parts = p.split(":");
        const title = parts.shift();
        const desc = parts.join(":");
        return `
          <div style="border:1px solid ${STYLE.insightBorder};border-radius:8px;padding:12px;background:${STYLE.insightBg};">
            <div style="font-weight:600;font-size:${STYLE.insightTitleSize};color:${STYLE.insightTitleColor};margin-bottom:4px;">
              ${title.trim()}
            </div>
            <div style="font-size:${STYLE.insightDescSize};color:${STYLE.insightDescColor};line-height:1.5;">
              ${desc.trim()}
            </div>
          </div>
        `;
      }).join('')}
    </div>
  `;
};

